-
+  // Fold icmp (X op C), X and icmp X, (X op C) patterns.
+  // For division/shift by constant C > 1 (or C >= 1 for shifts):
+  // - (X / C) == X --> X == 0 (only X=0 satisfies this, for C > 1)
+  // - (X >> C) == X --> X == 0 (only X=0 satisfies this, for C >= 1, unsigned shift)
+  // - (X / C) != X --> X != 0
+  // - (X / C) < X --> X > 0 (for positive X, division makes it smaller)
+  // - (X / C) <= X --> X >= 0
+  // - (X / C) > X --> X < 0
+  // - (X / C) >= X --> X <= 0
+  // For AShr:
+  // - (X >>s C) >= X --> X <= 0
+  // - (X >>s C) > X --> X < 0
+  // - (X >>s C) < X --> X > 0
+  // - (X >>s C) <= X is complex (X >= 0 or X = -1), don't simplify
+  // - (X >>s C) == X is complex (X == 0 or X == -1), don't simplify
+  // - (X >>s C) != X is complex (X != 0 and X != -1), don't simplify
+  const APInt *DivCst;
+  auto isDivShiftByMoreThanOne = [](Instruction *I, const APInt *C) -> bool {
+    if (I->getOpcode() == Instruction::LShr ||
+        I->getOpcode() == Instruction::AShr)
+      return !C->isZero();  // C >= 1 for shifts
+    return !C->isZero() && !C->isOne();  // C > 1 for division
+  };
+  if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+              BO0->getOpcode() == Instruction::UDiv ||
+              BO0->getOpcode() == Instruction::LShr ||
+              BO0->getOpcode() == Instruction::AShr) &&
+      Op1 == BO0->getOperand(0) &&
+      match(BO0->getOperand(1), m_APInt(DivCst)) &&
+      isDivShiftByMoreThanOne(BO0, DivCst)) {
+    bool IsAShr = BO0->getOpcode() == Instruction::AShr;
+    if (Pred == ICmpInst::ICMP_EQ) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_EQ, Op1,
+                               Constant::getNullValue(Op1->getType()));
+    } else if (Pred == ICmpInst::ICMP_NE) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_NE, Op1,
+                               Constant::getNullValue(Op1->getType()));
+    } else if (Pred == ICmpInst::ICMP_SLT) {
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                          Constant::getNullValue(Op1->getType()));
+    } else if (Pred == ICmpInst::ICMP_SLE) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_SGE, Op1,
+                               Constant::getNullValue(Op1->getType()));
+    } else if (Pred == ICmpInst::ICMP_SGT) {
+      if (IsAShr)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      else return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                               Constant::getNullValue(Op1->getType()));
+    } else if (Pred == ICmpInst::ICMP_SGE) {
+      if (IsAShr)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                            ConstantInt::get(Op1->getType(), 1));
+      else return new ICmpInst(ICmpInst::ICMP_SLE, Op1,
+                               Constant::getNullValue(Op1->getType()));
+    }
+  }
+  // Commuted case: icmp X, (X op C)
+  if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+              BO1->getOpcode() == Instruction::UDiv ||
+              BO1->getOpcode() == Instruction::LShr ||
+              BO1->getOpcode() == Instruction::AShr) &&
+      Op0 == BO1->getOperand(0) &&
+      match(BO1->getOperand(1), m_APInt(DivCst)) &&
+      isDivShiftByMoreThanOne(BO1, DivCst)) {
+    bool IsAShr = BO1->getOpcode() == Instruction::AShr;
+    if (Pred == ICmpInst::ICMP_EQ) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_EQ, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    } else if (Pred == ICmpInst::ICMP_NE) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_NE, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    } else if (Pred == ICmpInst::ICMP_SLT) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    } else if (Pred == ICmpInst::ICMP_SLE) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_SLE, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    } else if (Pred == ICmpInst::ICMP_SGT) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    } else if (Pred == ICmpInst::ICMP_SGE) {
+      if (IsAShr) /* skip */;
+      else return new ICmpInst(ICmpInst::ICMP_SGE, Op0,
+                               Constant::getNullValue(Op0->getType()));
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

